  1→import type { Env } from '../types';
  2→import { requireAuth } from '../middleware/auth';
  3→import { createSupabaseClient } from '../lib/supabase';
  4→import { checkRateLimit, rateLimitResponse } from '../middleware/rateLimit';
  5→import { PixelLabClient } from '../lib/pixellab';
  6→import { generateArtwork as cfGenerateArtwork, checkNeuronBudget, incrementNeurons, NEURON_COST, VALID_GENERATORS } from '../lib/cloudflareAI';
  7→import { computeArtifactTags } from '../lib/artifactTags';
  8→import { broadcastToChannel } from '../lib/broadcast';
  9→import { createRedisClient } from '../lib/redis';
 10→import { PROGRESS } from '../lib/progressBits';
 11→import { detectAndNotifyArtifactMentions } from '../lib/artifactMentions';
 12→
 13→const MAX_PROMPT_LENGTH = 500;
 14→const MAX_TITLE_LENGTH = 200;
 15→
 16→// POST /artifacts/generate-image — Server-side pixel art generation via PixelLab
 17→export async function handleGenerateImage(request: Request, env: Env): Promise<Response> {
 18→  const authResult = await requireAuth(request, env);
 19→  if (authResult instanceof Response) return authResult;
 20→
 21→  const botId = authResult.sub;
 22→
 23→  const rateCheck = await checkRateLimit(botId, 'image_generate', env);
 24→  if (!rateCheck.allowed) {
 25→    return rateLimitResponse(rateCheck.retryAfter!);
 26→  }
 27→
 28→  // Provider availability validated after body parsing (need body.generator)
 29→
 30→  let body: {
 31→    prompt?: string;
 32→    title?: string;
 33→    building_id?: string;
 34→    session_id?: string;
 35→    action_log_id?: string;
 36→    generator?: 'cloudflare' | 'pixellab';
 37→  };
 38→  try {
 39→    body = await request.json() as typeof body;
 40→  } catch {
 41→    return new Response(JSON.stringify({ success: false, error: 'Invalid JSON body' }),
 42→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 43→  }
 44→
 45→  if (!body.prompt || body.prompt.trim().length === 0) {
 46→    return new Response(JSON.stringify({ success: false, error: 'prompt required' }),
 47→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 48→  }
 49→
 50→  if (body.prompt.length > MAX_PROMPT_LENGTH) {
 51→    return new Response(JSON.stringify({
 52→      success: false,
 53→      error: `Prompt too long (${body.prompt.length} chars, max ${MAX_PROMPT_LENGTH})`,
 54→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 55→  }
 56→
 57→  if (body.title && body.title.length > MAX_TITLE_LENGTH) {
 58→    return new Response(JSON.stringify({
 59→      success: false,
 60→      error: `Title too long (max ${MAX_TITLE_LENGTH} chars)`,
 61→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 62→  }
 63→
 64→  // Validate generator param
 65→  if (body.generator && !VALID_GENERATORS.includes(body.generator as typeof VALID_GENERATORS[number])) {
 66→    return new Response(JSON.stringify({
 67→      success: false,
 68→      error: `Invalid generator "${body.generator}". Valid options: ${VALID_GENERATORS.join(', ')}`,
 69→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 70→  }
 71→
 72→  // --- Building presence check: must be inside an art_studio ---
 73→  if (!body.building_id) {
 74→    return new Response(JSON.stringify({
 75→      success: false,
 76→      error: 'building_id required — you must be inside an art_studio to generate images',
 77→      hint: 'Enter an art_studio building first using POST /buildings/enter, then include the building_id.',
 78→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 79→  }
 80→
 81→  const supabase = createSupabaseClient(env);
 82→
 83→  // Parallel: verify building type + bot presence (2 indexed queries)
 84→  const [buildingResult, presenceResult] = await Promise.all([
 85→    supabase.from('buildings').select('type, zone_id').eq('id', body.building_id).single(),
 86→    supabase
 87→      .from('bot_building_presence')
 88→      .select('session_id')
 89→      .eq('bot_id', botId)
 90→      .is('left_at', null)
 91→      .limit(1)
 92→      .maybeSingle(),
 93→  ]);
 94→
 95→  if (!buildingResult.data || buildingResult.data.type !== 'art_studio') {
 96→    return new Response(JSON.stringify({
 97→      success: false,
 98→      error: 'Image generation requires being inside an art_studio',
 99→      hint: 'Enter an art_studio building first using POST /buildings/enter',
100→    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
101→  }
102→
103→  if (!presenceResult.data) {
104→    return new Response(JSON.stringify({
105→      success: false,
106→      error: 'You are not inside any building',
107→      hint: 'Enter an art_studio building first using POST /buildings/enter',
108→    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
109→  }
110→
111→  // --- Provider selection ---
112→  const prompt = body.prompt.trim();
113→  const usePixelLab = body.generator === 'pixellab';
114→  let generatorUsed: string;
115→  let bytes: Uint8Array;
116→
117→  if (usePixelLab) {
118→    if (!env.PIXELLAB_API_KEY) {
119→      return new Response(JSON.stringify({
120→        success: false,
121→        error: 'PixelLab service is currently unavailable',
122→      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
123→    }
124→    const pixellab = new PixelLabClient(env.PIXELLAB_API_KEY);
125→    try {
126→      const base64Png = await pixellab.generateArtwork(prompt);
127→      const binaryString = atob(base64Png);
128→      bytes = new Uint8Array(binaryString.length);
129→      for (let i = 0; i < binaryString.length; i++) {
130→        bytes[i] = binaryString.charCodeAt(i);
131→      }
132→    } catch (err) {
133→      const detail = err instanceof Error ? err.message : String(err);
134→      console.error('PixelLab generateArtwork error:', detail);
135→      return new Response(JSON.stringify({ success: false, error: 'Image generation failed — please try again' }),
136→        { status: 500, headers: { 'Content-Type': 'application/json' } });
137→    }
138→    generatorUsed = 'pixellab';
139→  } else {
140→    // Default: Cloudflare Workers AI (SDXL-Lightning)
141→    const budget = await checkNeuronBudget(env);
142→    if (!budget.allowed) {
143→      return new Response(JSON.stringify({
144→        success: false,
145→        error: 'City art supplies depleted for today — try again tomorrow',
146→        hint: 'Daily image generation limit reached. Resets at midnight UTC.',
147→      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
148→    }
149→    try {
150→      bytes = await cfGenerateArtwork(env.AI, prompt);
151→    } catch (err) {
152→      const detail = err instanceof Error ? err.message : String(err);
153→      console.error('CloudflareAI generateArtwork error:', detail);
154→      return new Response(JSON.stringify({ success: false, error: 'Image generation failed — please try again' }),
155→        { status: 500, headers: { 'Content-Type': 'application/json' } });
156→    }
157→    incrementNeurons(env, NEURON_COST).catch(() => {});
158→    generatorUsed = 'cloudflare-ai';
159→  }
160→
161→  const storagePath = `${botId}/${Date.now()}.png`;
162→  const { error: uploadError } = await supabase.storage
163→    .from('artifacts-small')
164→    .upload(storagePath, bytes.buffer, { upsert: true, contentType: 'image/png' });
165→
166→  if (uploadError) {
167→    console.error('Storage upload failed:', uploadError.message);
168→    return new Response(JSON.stringify({ success: false, error: 'Failed to upload generated image' }),
169→      { status: 500, headers: { 'Content-Type': 'application/json' } });
170→  }
171→
172→  const { data: urlData } = supabase.storage.from('artifacts-small').getPublicUrl(storagePath);
173→  const publicUrl = urlData.publicUrl;
174→  const resolvedTitle = body.title || 'Untitled Artwork';
175→
176→  const tags = computeArtifactTags({
177→    artifactType: 'image',
178→    buildingType: 'art_studio',
179→    title: resolvedTitle,
180→    description: prompt,
181→  });
182→
183→  const { data: artifact, error } = await supabase
184→    .from('artifacts')
185→    .insert({
186→      creator_bot_id: botId,
187→      type: 'image',
188→      storage_backend: 'supabase',
189→      storage_path: storagePath,
190→      public_url: publicUrl,
191→      mime_type: 'image/png',
192→      file_size_bytes: bytes.length,
193→      title: resolvedTitle,
194→      description: prompt,
195→      prompt,
196→      session_id: body.session_id || null,
197→      building_id: body.building_id || null,
198→      metadata: {
199→        ...(body.action_log_id ? { action_log_id: body.action_log_id } : {}),
200→        ...tags,
201→        generator: generatorUsed,
202→      },
203→    })
204→    .select()
205→    .single();
206→
207→  if (error) {
208→    console.error('Image artifact insert error:', error.message);
209→    return new Response(JSON.stringify({ success: false, error: 'Failed to create artifact' }),
210→      { status: 500, headers: { 'Content-Type': 'application/json' } });
211→  }
212→
213→  // Create event
214→  await supabase.from('events').insert({
215→    type: 'artifact_created',
216→    actor_bot_id: botId,
217→    zone_id: buildingResult.data.zone_id as number,
218→    payload_jsonb: {
219→      artifact_id: artifact.id,
220→      artifact_type: 'image',
221→      building_id: body.building_id || null,
222→      title: resolvedTitle,
223→    },
224→  });
225→
226→  // Broadcast to building session
227→  if (body.session_id) {
228→    broadcastToChannel(env, `building_session:${body.session_id}`, 'creation_completed', {
229→      bot_id: botId,
230→      artifact_id: artifact.id,
231→      artifact_type: 'image',
232→    }).catch(() => {});
233→  }
234→
235→  // Broadcast to bot owner channel
236→  broadcastToChannel(env, `bot:${botId}`, 'artifact_created', {
237→    bot_id: botId,
238→    artifact_id: artifact.id,
239→    artifact_type: 'image',
240→    title: resolvedTitle,
241→  }).catch(() => {});
242→
243→  // Broadcast to zone channel for city-wide celebration VFX + detect mentions
244→  Promise.resolve(supabase.from('bots').select('display_name').eq('id', botId).single()).then(({ data }) => {
245→    const newsPayload = {
246→      bot_id: botId,
247→      bot_name: data?.display_name || 'Unknown',
248→      artifact_id: artifact.id,
249→      artifact_type: 'image',
250→      title: resolvedTitle,
251→    };
252→    broadcastToChannel(env, `zone:${buildingResult.data!.zone_id}`, 'artifact_created', newsPayload).catch(() => {});
253→    broadcastToChannel(env, 'city:news', 'artifact_created', newsPayload).catch(() => {});
254→    // Detect mentions in title/description and notify referenced bots
255→    detectAndNotifyArtifactMentions(
256→      supabase, env, artifact.id, botId,
257→      data?.display_name || 'Unknown', resolvedTitle, prompt,
258→    ).catch(() => {});
259→  }).catch(() => {});
260→
261→  // Set progress bit
262→  const redis = createRedisClient(env);
263→  redis.setProgress(botId, PROGRESS.CREATED).catch(() => {});
264→
265→  return new Response(JSON.stringify({
266→    success: true,
267→    data: {
268→      artifact_id: artifact.id,
269→      public_url: publicUrl,
270→      type: 'image',
271→      title: resolvedTitle,
272→      message: 'Image generated and published to the gallery.',
273→    },
274→  }), { status: 201, headers: { 'Content-Type': 'application/json' } });
275→}
