  1→const BASE_URL = 'https://api.pixellab.ai/v1';
  2→
  3→export class PixelLabClient {
  4→  constructor(private apiKey: string) {}
  5→
  6→  /**
  7→   * Generate a south-facing character from a text prompt.
  8→   * Returns base64-encoded PNG.
  9→   */
 10→  async generateCharacter(prompt: string): Promise<string> {
 11→    const resp = await fetch(`${BASE_URL}/generate-image-pixflux`, {
 12→      method: 'POST',
 13→      headers: {
 14→        'Content-Type': 'application/json',
 15→        Authorization: `Bearer ${this.apiKey}`,
 16→      },
 17→      body: JSON.stringify({
 18→        description: prompt,
 19→        image_size: { width: 48, height: 48 },
 20→        no_background: true,
 21→        direction: 'south',
 22→        view: 'low top-down',
 23→        outline: 'single color black outline',
 24→        shading: 'basic shading',
 25→        detail: 'medium detail',
 26→        isometric: false,
 27→      }),
 28→    });
 29→
 30→    if (!resp.ok) {
 31→      const text = await resp.text();
 32→      throw new Error(`PixelLab generate failed (${resp.status}): ${text}`);
 33→    }
 34→
 35→    const data = (await resp.json()) as { image: { base64: string } };
 36→    return data.image.base64;
 37→  }
 38→
 39→  /**
 40→   * Generate pixel art from a description (for NPC artifact creation).
 41→   * Returns base64-encoded PNG.
 42→   */
 43→  async generateArtwork(description: string): Promise<string> {
 44→    const resp = await fetch(`${BASE_URL}/generate-image-pixflux`, {
 45→      method: 'POST',
 46→      headers: {
 47→        'Content-Type': 'application/json',
 48→        Authorization: `Bearer ${this.apiKey}`,
 49→      },
 50→      body: JSON.stringify({
 51→        description,
 52→        image_size: { width: 64, height: 64 },
 53→        view: 'side',
 54→        shading: 'flat shading',
 55→        outline: 'single color black outline',
 56→        detail: 'highly detailed',
 57→        isometric: false,
 58→      }),
 59→    });
 60→
 61→    if (!resp.ok) {
 62→      const text = await resp.text();
 63→      throw new Error(`PixelLab artwork generate failed (${resp.status}): ${text}`);
 64→    }
 65→
 66→    const data = (await resp.json()) as { image: { base64: string } };
 67→    return data.image.base64;
 68→  }
 69→
 70→  /**
 71→   * Generate a furniture sprite from a text description.
 72→   * Returns base64-encoded PNG (64x64, isometric, transparent background).
 73→   */
 74→  async generateFurnitureSprite(description: string): Promise<string> {
 75→    const resp = await fetch(`${BASE_URL}/generate-image-pixflux`, {
 76→      method: 'POST',
 77→      headers: {
 78→        'Content-Type': 'application/json',
 79→        Authorization: `Bearer ${this.apiKey}`,
 80→      },
 81→      body: JSON.stringify({
 82→        description: `Pixel art furniture item: ${description}. Isometric view, transparent background`,
 83→        image_size: { width: 64, height: 64 },
 84→        no_background: true,
 85→        view: 'low top-down',
 86→        shading: 'basic shading',
 87→        outline: 'single color black outline',
 88→        detail: 'medium detail',
 89→        isometric: true,
 90→      }),
 91→    });
 92→
 93→    if (!resp.ok) {
 94→      const text = await resp.text();
 95→      throw new Error(`PixelLab furniture generate failed (${resp.status}): ${text}`);
 96→    }
 97→
 98→    const data = (await resp.json()) as { image: { base64: string } };
 99→    return data.image.base64;
100→  }
101→
102→  /**
103→   * Rotate an existing character image to a new direction.
104→   * Returns base64-encoded PNG.
105→   */
106→  async rotateCharacter(
107→    fromBase64: string,
108→    fromDir: string,
109→    toDir: string,
110→  ): Promise<string> {
111→    const resp = await fetch(`${BASE_URL}/rotate`, {
112→      method: 'POST',
113→      headers: {
114→        'Content-Type': 'application/json',
115→        Authorization: `Bearer ${this.apiKey}`,
116→      },
117→      body: JSON.stringify({
118→        image: { base64: fromBase64 },
119→        image_size: { width: 48, height: 48 },
120→        from_direction: fromDir,
121→        to_direction: toDir,
122→        no_background: true,
123→        view: 'low top-down',
124→        outline: 'single color black outline',
125→        shading: 'basic shading',
126→        detail: 'medium detail',
127→        isometric: false,
128→      }),
129→    });
130→
131→    if (!resp.ok) {
132→      const text = await resp.text();
133→      throw new Error(`PixelLab rotate failed (${resp.status}): ${text}`);
134→    }
135→
136→    const data = (await resp.json()) as { image: { base64: string } };
137→    return data.image.base64;
138→  }
139→
140→  /**
141→   * Generate animation frames for a character.
142→   * Returns array of base64-encoded PNGs.
143→   */
144→  async animateCharacter(
145→    refBase64: string,
146→    action: string,
147→    direction: string,
148→    nFrames: number,
149→  ): Promise<string[]> {
150→    const resp = await fetch(`${BASE_URL}/animate-with-text`, {
151→      method: 'POST',
152→      headers: {
153→        'Content-Type': 'application/json',
154→        Authorization: `Bearer ${this.apiKey}`,
155→      },
156→      body: JSON.stringify({
157→        reference_image: { base64: refBase64 },
158→        image_size: { width: 48, height: 48 },
159→        action,
160→        direction,
161→        n_frames: nFrames,
162→        no_background: true,
163→        view: 'low top-down',
164→        outline: 'single color black outline',
165→        shading: 'basic shading',
166→        detail: 'medium detail',
167→        isometric: false,
168→      }),
169→    });
170→
171→    if (!resp.ok) {
172→      const text = await resp.text();
173→      throw new Error(`PixelLab animate failed (${resp.status}): ${text}`);
174→    }
175→
176→    const data = (await resp.json()) as { images: Array<{ base64: string }> };
177→    return data.images.map((img) => img.base64);
178→  }
179→}
