 1→import type { Env } from '../types';
 2→import { createRedisClient } from './redis';
 3→
 4→// SDXL-Lightning is free (0 neurons) during beta.
 5→// When beta ends, switch to FLUX 1 Schnell at ~58 neurons per 1024x1024.
 6→const NEURONS_PER_IMAGE = 0;
 7→const DAILY_NEURON_CAP = 10_000;
 8→const NEURON_KEY_TTL = 172_800; // 48h — safely covers the UTC day boundary
 9→
10→const MODEL_ID = '@cf/bytedance/stable-diffusion-xl-lightning';
11→
12→function neuronKey(): string {
13→  const d = new Date();
14→  const yyyy = d.getUTCFullYear();
15→  const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
16→  const dd = String(d.getUTCDate()).padStart(2, '0');
17→  return `cfai:neurons:${yyyy}-${mm}-${dd}`;
18→}
19→
20→/** Check whether the daily neuron budget allows another generation. */
21→export async function checkNeuronBudget(env: Env): Promise<{ allowed: boolean; remaining: number }> {
22→  if (NEURONS_PER_IMAGE === 0) return { allowed: true, remaining: DAILY_NEURON_CAP };
23→  const redis = createRedisClient(env);
24→  const raw = await redis.get(neuronKey());
25→  const used = raw ? parseInt(raw, 10) : 0;
26→  const remaining = Math.max(0, DAILY_NEURON_CAP - used);
27→  return { allowed: remaining >= NEURONS_PER_IMAGE, remaining };
28→}
29→
30→/** Record neurons consumed after a successful generation. */
31→export async function incrementNeurons(env: Env, count: number): Promise<void> {
32→  if (count === 0) return;
33→  const redis = createRedisClient(env);
34→  const key = neuronKey();
35→  await redis.incrBy(key, count);
36→  await redis.expire(key, NEURON_KEY_TTL);
37→}
38→
39→/**
40→ * Generate artwork via Cloudflare Workers AI (SDXL-Lightning).
41→ * Returns raw PNG bytes as Uint8Array — avoids base64 round-trip overhead.
42→ */
43→export async function generateArtwork(ai: Ai, prompt: string): Promise<Uint8Array> {
44→  const response = await ai.run(MODEL_ID, {
45→    prompt,
46→    width: 1024,
47→    height: 1024,
48→    num_steps: 8,
49→    guidance: 7.5,
50→  });
51→
52→  return toUint8Array(response);
53→}
54→
55→/**
56→ * Generate a furniture sprite via Cloudflare Workers AI (SDXL-Lightning).
57→ * Returns raw PNG bytes as Uint8Array — avoids base64 round-trip overhead.
58→ */
59→export async function generateFurnitureSprite(ai: Ai, prompt: string): Promise<Uint8Array> {
60→  const response = await ai.run(MODEL_ID, {
61→    prompt: `Pixel art furniture item: ${prompt}. Isometric view, transparent background, game asset`,
62→    width: 512,
63→    height: 512,
64→    num_steps: 8,
65→    guidance: 7.5,
66→  });
67→
68→  return toUint8Array(response);
69→}
70→
71→/** Normalize Workers AI response (ReadableStream | ArrayBuffer) to Uint8Array. */
72→function toUint8Array(response: unknown): Uint8Array {
73→  if (response instanceof ReadableStream) {
74→    // Shouldn't happen synchronously — caller must await
75→    throw new Error('Unexpected ReadableStream from AI model; use generateArtworkStream instead');
76→  }
77→  if (response instanceof ArrayBuffer) {
78→    return new Uint8Array(response);
79→  }
80→  if (response instanceof Uint8Array) {
81→    return response;
82→  }
83→  // Some models return a raw array-like; attempt conversion
84→  throw new Error(`Unexpected AI response type: ${typeof response}`);
85→}
86→
87→/** Accepted values for the generator body param. */
88→export const VALID_GENERATORS = ['cloudflare', 'pixellab'] as const;
89→export type GeneratorType = (typeof VALID_GENERATORS)[number];
90→
91→/** Cost per image in neurons (exported for tests). */
92→export const NEURON_COST = NEURONS_PER_IMAGE;
