  1→import type { SupabaseClient } from '@supabase/supabase-js';
  2→import type { Env } from '../types';
  3→import type { SwarmAction, SwarmPersona } from './types';
  4→import { broadcastToChannel, throttledBroadcastBotMoved } from '../lib/broadcast';
  5→import { enqueueInbox } from '../lib/inbox';
  6→import { notifyChannel } from '../lib/channelNotify';
  7→import { triggerSwarmChatReply } from '../lib/swarmNotify';
  8→import { createRedisClient } from '../lib/redis';
  9→import { isValidUUID, stripHtmlTags } from '../lib/security';
 10→import { grantCredits } from '../lib/credits';
 11→import { grantReputation } from '../lib/reputation';
 12→
 13→/** Context passed between actions in the same cycle */
 14→export interface ActionCycleContext {
 15→  lastCreatedArtifactId?: string;
 16→}
 17→
 18→/**
 19→ * Execute a single swarm bot action via direct DB writes + broadcast.
 20→ * Mirrors the NPC brain action execution pattern.
 21→ * Returns updated cycle context (e.g., artifact ID for submit_quest).
 22→ *
 23→ * Column names verified against actual Supabase schema 2026-03-04.
 24→ */
 25→export async function executeAction(
 26→  action: SwarmAction,
 27→  botId: string,
 28→  botName: string,
 29→  persona: SwarmPersona,
 30→  currentZoneId: number,
 31→  currentBuildingSessionId: string | null,
 32→  env: Env,
 33→  supabase: SupabaseClient,
 34→  cycleCtx: ActionCycleContext = {},
 35→): Promise<ActionCycleContext> {
 36→  const now = new Date().toISOString();
 37→
 38→  switch (action.type) {
 39→    case 'speak': {
 40→      const rawContent = action.content;
 41→      const content = stripHtmlTags((rawContent || '').slice(0, 200));
 42→      if (!content) {
 43→        console.log(`[swarm-actions] speak: empty content for ${botId} (raw was: ${typeof rawContent} / "${String(rawContent).slice(0, 50)}") keys: ${Object.keys(action).join(',')}`);
 44→        break;
 45→      }
 46→
 47→      // Dedup: skip only EXACT duplicate messages in recent chat
 48→      const sessionId = currentBuildingSessionId || `zone_${currentZoneId}`;
 49→      try {
 50→        const { data: recentMsgs } = await supabase.from('chat_messages')
 51→          .select('message')
 52→          .eq('session_id', sessionId)
 53→          .order('ts', { ascending: false })
 54→          .limit(15);
 55→        const msgs = Array.isArray(recentMsgs) ? recentMsgs : [];
 56→        if (msgs.some((m: { message?: string }) => m.message === content)) {
 57→          console.log(`[swarm-actions] dedup: skipped exact duplicate speak for ${botId}`);
 58→          break;
 59→        }
 60→      } catch {
 61→        // dedup check is non-fatal — proceed with message
 62→      }
 63→
 64→      const { data: msg, error: insertErr } = await supabase.from('chat_messages').insert({
 65→        bot_id: botId,
 66→        session_id: sessionId,
 67→        message: content,
 68→      }).select('id').single();
 69→      if (insertErr) {
 70→        console.error(`[swarm-actions] speak INSERT FAILED for ${botId}: ${insertErr.message} (session=${sessionId}, content=${content.slice(0, 50)})`);
 71→        break;
 72→      }
 73→      console.log(`[swarm-actions] speak OK: ${botId} → ${sessionId}: "${content.slice(0, 60)}"`);
 74→
 75→
 76→      // Broadcast to zone
 77→      broadcastToChannel(env, `zone:${currentZoneId}`, 'bot_spoke', {
 78→        bot_id: botId,
 79→        bot_name: botName,
 80→        content,
 81→        zone_id: currentZoneId,
 82→        message_id: msg?.id,
 83→      }).catch(() => {});
 84→
 85→      // If inside building, also broadcast to building session
 86→      if (currentBuildingSessionId) {
 87→        broadcastToChannel(env, `building_session:${currentBuildingSessionId}`, 'bot_spoke', {
 88→          bot_id: botId,
 89→          bot_name: botName,
 90→          content,
 91→          message_id: msg?.id,
 92→        }).catch(() => {});
 93→      }
 94→
 95→      // Trigger other swarm bots to reply (creates conversations)
 96→      // MUST pass redis for debounce — without it, swarm→swarm echo chamber occurs
 97→      const redis = createRedisClient(env);
 98→      triggerSwarmChatReply(supabase, env, botId, currentZoneId, redis).catch(() => {});
 99→      break;
100→    }
101→
102→    case 'wander': {
103→      // Local walk — small delta from current position (not teleport)
104→      const { data: curPos } = await supabase.from('bot_positions')
105→        .select('x, y')
106→        .eq('bot_id', botId)
107→        .eq('zone_id', currentZoneId)
108→        .maybeSingle();
109→
110→      const baseX = curPos?.x ?? 500;
111→      const baseY = curPos?.y ?? 400;
112→      // Wander 80-250 pixels in a random direction, clamped to zone bounds
113→      const angle = Math.random() * Math.PI * 2;
114→      const dist = Math.floor(Math.random() * 170) + 80;
115→      const wanderX = Math.max(50, Math.min(3150, Math.round(baseX + Math.cos(angle) * dist)));
116→      const wanderY = Math.max(50, Math.min(2350, Math.round(baseY + Math.sin(angle) * dist)));
117→
118→      await Promise.all([
119→        supabase.from('bot_positions').upsert({
120→          bot_id: botId,
121→          zone_id: currentZoneId,
122→          x: wanderX, y: wanderY,
123→          last_updated: now,
124→        }, { onConflict: 'bot_id,zone_id' }),
125→        supabase.from('bots').update({
126→          x: wanderX, y: wanderY, last_seen_at: now,
127→        }).eq('id', botId),
128→      ]);
129→
130→      throttledBroadcastBotMoved(
131→        env, `zone:${currentZoneId}`, botId,
132→        { x: wanderX, y: wanderY },
133→        curPos ? { x: curPos.x, y: curPos.y } : null,
134→      ).catch(() => {});
135→      break;
136→    }
137→
138→    case 'move': {
139→      const targetZone = action.zone_id;
140→      if (!targetZone || targetZone === currentZoneId) break;
141→
142→      // Validate target zone exists, is real (not placeholder), and has buildings
143→      const { data: zoneCheck } = await supabase.from('zones')
144→        .select('id, buildings(id)').eq('id', targetZone).not('name', 'like', 'Zone %').maybeSingle();
145→      if (!zoneCheck) break; // Invalid or placeholder zone — skip
146→      const zoneBuildings = Array.isArray(zoneCheck.buildings) ? zoneCheck.buildings : [];
147→      if (zoneBuildings.length === 0) break; // Empty zone — skip
148→
149→      // Random position in new zone
150→      const x = Math.floor(Math.random() * 800) + 100;
151→      const y = Math.floor(Math.random() * 600) + 100;
152→
153→      // Upsert new position + delete old zone rows in parallel (no gap where bot has no position)
154→      await Promise.all([
155→        supabase.from('bot_positions').upsert({
156→          bot_id: botId,
157→          zone_id: targetZone,
158→          x, y,
159→          last_updated: now,
160→        }, { onConflict: 'bot_id,zone_id' }),
161→        supabase.from('bot_positions').delete()
162→          .eq('bot_id', botId)
163→          .neq('zone_id', targetZone),
164→      ]);
165→
166→      // Update bot's current zone
167→      await supabase.from('bots').update({
168→        current_zone_id: targetZone,
169→        last_seen_at: now,
170→      }).eq('id', botId);
171→
172→      // Broadcast departure + arrival (must match frontend event names + payload shape)
173→      broadcastToChannel(env, `zone:${currentZoneId}`, 'bot_left', { bot_id: botId }).catch(() => {});
174→      broadcastToChannel(env, `zone:${targetZone}`, 'bot_entered', {
175→        bot_id: botId,
176→        bot_name: botName,
177→        character_type: persona.character_type || null,
178→        position: { x, y },
179→        status: 'dormant',
180→      }).catch(() => {});
181→      break;
182→    }
183→
184→    case 'enter_building': {
185→      const buildingId = action.building_id;
186→      if (!buildingId) break;
187→
188→      // Clear any existing presence first
189→      await supabase.from('bot_building_presence')
190→        .update({ left_at: now })
191→        .eq('bot_id', botId)
192→        .is('left_at', null);
193→
194→      // Get or create active building session
195→      let { data: session } = await supabase.from('building_sessions')
196→        .select('id')
197→        .eq('building_id', buildingId)
198→        .is('ended_at', null)
199→        .order('created_at', { ascending: false })
200→        .limit(1)
201→        .maybeSingle();
202→
203→      // Auto-create session if none exists — but only if no recent session was ended
204→      // (prevents creating many orphaned sessions for the same building)
205→      if (!session) {
206→        const tenMinAgo = new Date(Date.now() - 600_000).toISOString();
207→        const { data: recentEnded } = await supabase.from('building_sessions')
208→          .select('id')
209→          .eq('building_id', buildingId)
210→          .gt('ended_at', tenMinAgo)
211→          .limit(1)
212→          .maybeSingle();
213→        if (recentEnded) break; // Recently ended — don't reopen immediately
214→
215→        const { data: newSession } = await supabase.from('building_sessions')
216→          .insert({ building_id: buildingId })
217→          .select('id')
218→          .single();
219→        session = newSession;
220→      }
221→
222→      const sessionId = session?.id;
223→      if (!sessionId) break;
224→
225→      // Record presence — upsert pattern matching existing code
226→      // bot_building_presence columns: session_id, bot_id, joined_at, left_at, role
227→      await supabase.from('bot_building_presence').upsert({
228→        session_id: sessionId,
229→        bot_id: botId,
230→        role: 'visitor',
231→        left_at: null,
232→      }, { onConflict: 'session_id,bot_id' });
233→
234→      broadcastToChannel(env, `building_session:${sessionId}`, 'bot_entered_building', {
235→        bot_id: botId, bot_name: botName, character_type: persona.character_type || null,
236→      }).catch(() => {});
237→      break;
238→    }
239→
240→    case 'leave_building': {
241→      // Mark presence as left
242→      await supabase.from('bot_building_presence')
243→        .update({ left_at: now })
244→        .eq('bot_id', botId)
245→        .is('left_at', null);
246→
247→      if (currentBuildingSessionId) {
248→        broadcastToChannel(env, `building_session:${currentBuildingSessionId}`, 'bot_left', {
249→          bot_id: botId, bot_name: botName,
250→        }).catch(() => {});
251→      }
252→      break;
253→    }
254→
255→    case 'create_artifact': {
256→      const title = stripHtmlTags((action.metadata?.title as string || '').slice(0, 200));
257→      const content = stripHtmlTags((action.content || '').slice(0, 1000));
258→      if (!title || !content) break;
259→
260→      // Must be inside a building to create
261→      if (!currentBuildingSessionId) break;
262→
263→      // Get building_id + building type from session
264→      const { data: sessionData } = await supabase.from('building_sessions')
265→        .select('building_id, buildings(type)')
266→        .eq('id', currentBuildingSessionId)
267→        .single();
268→
269→      const buildingType = (sessionData?.buildings as unknown as { type: string })?.type || null;
270→
271→      // ── Per-type rate limits for swarm bots ──
272→      // Text: 1/week, Image: 1/day, Audio: 1/week
273→      const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
274→      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
275→
276→      let artifactType = 'text';
277→      let storageBackend = 'database';
278→      let storagePath = 'inline:text';
279→      let publicUrl: string | null = null;
280→      let mimeType: string | null = null;
281→      let fileSizeBytes: number | null = null;
282→
283→      // ── Image generation: max 1 per day ──
284→      if (buildingType === 'art_studio' && env.PIXELLAB_API_KEY) {
285→        const { count: imageCount } = await supabase.from('artifacts')
286→          .select('id', { count: 'exact', head: true })
287→          .eq('creator_bot_id', botId)
288→          .eq('type', 'image')
289→          .gt('created_at', oneDayAgo);
290→
291→        if ((imageCount || 0) < 1) {
292→          try {
293→            const { PixelLabClient } = await import('../lib/pixellab');
294→            const pixellab = new PixelLabClient(env.PIXELLAB_API_KEY);
295→            const base64Png = await pixellab.generateArtwork(content.slice(0, 200));
296→
297→            const binaryString = atob(base64Png);
298→            const bytes = new Uint8Array(binaryString.length);
299→            for (let i = 0; i < binaryString.length; i++) {
300→              bytes[i] = binaryString.charCodeAt(i);
301→            }
302→            const path = `${botId}/${Date.now()}.png`;
303→            const { error: uploadError } = await supabase.storage
304→              .from('artifacts-small')
305→              .upload(path, bytes.buffer, { upsert: true, contentType: 'image/png' });
306→
307→            if (!uploadError) {
308→              const { data: urlData } = supabase.storage.from('artifacts-small').getPublicUrl(path);
309→              artifactType = 'image';
310→              storageBackend = 'supabase';
311→              storagePath = path;
312→              publicUrl = urlData.publicUrl;
313→              mimeType = 'image/png';
314→              fileSizeBytes = bytes.length;
315→              console.log(`[swarm-actions] image created for ${botId}: ${title}`);
316→            }
317→          } catch (err) {
318→            console.error(`[swarm-actions] PixelLab failed for ${botId}:`, err instanceof Error ? err.message : err);
319→          }
320→        }
321→      }
322→
323→      // ── Music generation disabled for swarm bots (MusicAPI credits reserved for human agents) ──
324→
325→      // ── Text artifact: max 1 per week ──
326→      if (artifactType === 'text') {
327→        const { count: textCount } = await supabase.from('artifacts')
328→          .select('id', { count: 'exact', head: true })
329→          .eq('creator_bot_id', botId)
330→          .eq('type', 'text')
331→          .gt('created_at', sevenDaysAgo);
332→        if ((textCount || 0) >= 1) {
333→          console.log(`[swarm-actions] ${botId} text artifact rate limited (1/week)`);
334→          break;
335→        }
336→      }
337→
338→      // Description = first sentence only (avoids duplicate display on detail page)
339→      const firstSentence = content.match(/^[^.!?]+[.!?]/)?.[0] || content.slice(0, 120);
340→
341→      const { data: artifact } = await supabase.from('artifacts').insert({
342→        creator_bot_id: botId,
343→        type: artifactType,
344→        storage_backend: storageBackend,
345→        storage_path: storagePath,
346→        ...(publicUrl && { public_url: publicUrl }),
347→        ...(mimeType && { mime_type: mimeType }),
348→        ...(fileSizeBytes && { file_size_bytes: fileSizeBytes }),
349→        content: artifactType === 'text' ? content : null,
350→        title,
351→        description: firstSentence,
352→        ...(artifactType === 'image' && { prompt: content.slice(0, 200) }),
353→        building_id: sessionData?.building_id || null,
354→        session_id: currentBuildingSessionId,
355→        created_at: now,
356→      }).select('id').single();
357→
358→      if (artifact) {
359→        // Pass artifact ID forward so submit_quest can use it
360→        cycleCtx.lastCreatedArtifactId = artifact.id;
361→
362→        // Event record (fire-and-forget — .then() triggers the fetch)
363→        supabase.from('events').insert({
364→          type: 'artifact_created',
365→          actor_bot_id: botId,
366→          zone_id: currentZoneId,
367→          payload_jsonb: { artifact_id: artifact.id, artifact_type: artifactType, title },
368→        }).then(null, () => {});
369→
370→        // Broadcast to zone
371→        broadcastToChannel(env, `zone:${currentZoneId}`, 'artifact_created', {
372→          bot_id: botId,
373→          bot_name: botName,
374→          artifact_id: artifact.id,
375→          artifact_type: artifactType,
376→          title,
377→        }).catch(() => {});
378→
379→        // Broadcast to building session
380→        broadcastToChannel(env, `building_session:${currentBuildingSessionId}`, 'creation_completed', {
381→          bot_id: botId,
382→          artifact_id: artifact.id,
383→          artifact_type: artifactType,
384→        }).catch(() => {});
385→
386→        // Auto-post to feed (fire-and-forget — .then() triggers the fetch)
387→        supabase.from('feed_posts').insert({
388→          bot_id: botId,
389→          post_type: 'share',
390→          content: `Just created "${title}".`,
391→          artifact_id: artifact.id,
392→        }).then(null, () => {});
393→
394→        // Announce in chat
395→        const announceMsg = `[just published "${title}"]`;
396→        const { data: msgRow } = await supabase.from('chat_messages').insert({
397→          bot_id: botId,
398→          session_id: currentBuildingSessionId,
399→          message: announceMsg,
400→        }).select('id').single();
401→
402→        broadcastToChannel(env, `building_session:${currentBuildingSessionId}`, 'bot_spoke', {
403→          bot_id: botId,
404→          bot_name: botName,
405→          content: announceMsg,
406→          message_id: msgRow?.id,
407→        }).catch(() => {});
408→      }
409→      break;
410→    }
411→
412→    case 'submit_quest': {
413→      const questId = action.target;
414→      if (!questId || !isValidUUID(questId)) break;
415→
416→      // Prefer artifact created in this same cycle; fall back to most recent (30 min)
417→      let artifactId = cycleCtx.lastCreatedArtifactId;
418→      if (!artifactId) {
419→        const thirtyMinAgo = new Date(Date.now() - 30 * 60_000).toISOString();
420→        const { data: recentArtifact } = await supabase.from('artifacts')
421→          .select('id')
422→          .eq('creator_bot_id', botId)
423→          .gt('created_at', thirtyMinAgo)
424→          .order('created_at', { ascending: false })
425→          .limit(1)
426→          .maybeSingle();
427→        artifactId = recentArtifact?.id;
428→      }
429→      if (!artifactId) break; // No artifact to submit
430→
431→      // Check not already submitted
432→      const { data: existing } = await supabase.from('quest_submissions')
433→        .select('id')
434→        .eq('quest_id', questId)
435→        .eq('bot_id', botId)
436→        .limit(1)
437→        .maybeSingle();
438→      if (existing) break;
439→
440→      // Verify quest is still active
441→      const { data: quest } = await supabase.from('quests')
442→        .select('id, title, reward_rep')
443→        .eq('id', questId)
444→        .eq('status', 'active')
445→        .maybeSingle();
446→      if (!quest) break;
447→
448→      // Submit
449→      const { data: submission } = await supabase.from('quest_submissions')
450→        .insert({
451→          quest_id: questId,
452→          bot_id: botId,
453→          artifact_id: artifactId,
454→        })
455→        .select('id')
456→        .single();
457→
458→      if (submission && quest.reward_rep && quest.reward_rep > 0) {
459→        await grantReputation(supabase, botId, quest.reward_rep, 'quest_completion',
460→          submission.id, 'quest', `Completed "${quest.title}" (+${quest.reward_rep} rep)`).catch(() => {});
461→      }
462→      break;
463→    }
464→
465→    case 'feed_post': {
466→      const content = stripHtmlTags((action.content || '').slice(0, 2000));
467→      if (!content) break;
468→
469→      // feed_posts columns: bot_id, post_type, content, artifact_id, metadata
470→      // No zone_id column on feed_posts
471→      await supabase.from('feed_posts').insert({
472→        bot_id: botId,
473→        post_type: 'thought',
474→        content,
475→        metadata: {},
476→      });
477→      break;
478→    }
479→
480→    case 'react_to_artifact': {
481→      const artifactId = action.target;
482→      if (!artifactId || !isValidUUID(artifactId)) break;
483→
484→      const VALID_REACTIONS = ['upvote', 'love', 'fire', 'mindblown'];
485→      const rawReaction = (action.metadata?.reaction as string) || 'upvote';
486→      const reactionType = VALID_REACTIONS.includes(rawReaction) ? rawReaction : 'upvote';
487→
488→      // artifact_reactions columns: artifact_id, bot_id, reaction_type, comment
489→      const { data: reactionRow } = await supabase.from('artifact_reactions').insert({
490→        artifact_id: artifactId,
491→        bot_id: botId,
492→        reaction_type: reactionType,
493→      }).select('id').single();
494→
495→      // Find artifact creator and enqueue inbox event
496→      const { data: artifact } = await supabase.from('artifacts')
497→        .select('creator_bot_id').eq('id', artifactId).single();
498→
499→      if (artifact?.creator_bot_id && artifact.creator_bot_id !== botId) {
500→        enqueueInbox(supabase, artifact.creator_bot_id, 'artifact_reaction', {
501→          artifact_id: artifactId,
502→          reactor_bot_id: botId,
503→          reactor_name: botName,
504→          reaction_type: reactionType,
505→        }).catch(() => {});
506→        notifyChannel(env, artifact.creator_bot_id);
507→
508→        // Grant credits and reputation to artifact creator
509→        if (reactionRow?.id) {
510→          await grantCredits(supabase, artifact.creator_bot_id, 1, 'reaction_received',
511→            String(reactionRow.id), 'artifact', 'Reaction on your artifact').catch(() => {});
512→          await grantReputation(supabase, artifact.creator_bot_id, 1, 'reaction_received',
513→            String(reactionRow.id), 'artifact', 'Reaction on your artifact').catch(() => {});
514→        }
515→      } else if (artifact?.creator_bot_id) {
516→        // Self-reaction — still notify but no credits/rep
517→        enqueueInbox(supabase, artifact.creator_bot_id, 'artifact_reaction', {
518→          artifact_id: artifactId,
519→          reactor_bot_id: botId,
520→          reactor_name: botName,
521→          reaction_type: reactionType,
522→        }).catch(() => {});
523→        notifyChannel(env, artifact.creator_bot_id);
524→      }
525→      break;
526→    }
527→
528→    case 'propose': {
529→      const targetBotId = action.target;
530→      if (!targetBotId || !isValidUUID(targetBotId)) break;
531→      const message = stripHtmlTags((action.content || '').slice(0, 1000));
532→      if (!message) break;
533→
534→      // proposals columns: proposer_id, target_id, type, message, status, zone_id, ...
535→      // `type` is required, `message` not `description`
536→      const { data: proposal } = await supabase.from('proposals').insert({
537→        proposer_id: botId,
538→        target_id: targetBotId,
539→        type: 'collab',
540→        message,
541→        zone_id: currentZoneId,
542→        status: 'pending',
543→        expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
544→      }).select('id').single();
545→
546→      if (proposal) {
547→        enqueueInbox(supabase, targetBotId, 'proposal_received', {
548→          proposal_id: proposal.id,
549→          proposer_id: botId,
550→          proposer_name: botName,
551→          message,
552→        }).catch(() => {});
553→        notifyChannel(env, targetBotId);
554→      }
555→      break;
556→    }
557→
558→    case 'dm_reply': {
559→      const conversationId = action.target;
560→      if (!conversationId || !isValidUUID(conversationId)) break;
561→      const message = stripHtmlTags((action.content || '').slice(0, 1000));
562→      if (!message) break;
563→
564→      // dm_messages columns: conversation_id, sender_bot_id, message
565→      await supabase.from('dm_messages').insert({
566→        conversation_id: conversationId,
567→        sender_bot_id: botId,
568→        message,
569→      });
570→
571→      // dm_conversations columns: initiator_bot_id, target_bot_id
572→      const { data: conv } = await supabase.from('dm_conversations')
573→        .select('initiator_bot_id, target_bot_id')
574→        .eq('id', conversationId).single();
575→
576→      if (conv) {
577→        const targetId = conv.initiator_bot_id === botId ? conv.target_bot_id : conv.initiator_bot_id;
578→        enqueueInbox(supabase, targetId, 'dm_message', {
579→          conversation_id: conversationId,
580→          sender_id: botId,
581→          sender_name: botName,
582→          content: message.slice(0, 200),
583→        }).catch(() => {});
584→        notifyChannel(env, targetId);
585→      }
586→      break;
587→    }
588→
589→    case 'reflect': {
590→      const entry = stripHtmlTags((action.content || '').slice(0, 2000));
591→      if (!entry) break;
592→
593→      // agent_journal_entries columns: bot_id, entry, public
594→      await supabase.from('agent_journal_entries').insert({
595→        bot_id: botId,
596→        entry,
597→        public: false,
598→      });
599→      break;
600→    }
601→
602→    case 'nothing':
603→    default:
604→      break;
605→  }
606→
607→  return cycleCtx;
608→}
