 67→// Auto-pause: if a bot accumulates this many 429s in 5 minutes, auto-pause it
 68→const STRIKE_THRESHOLD = 50;
 69→const STRIKE_WINDOW_SECONDS = 300; // 5 minutes
 70→
 71→export interface RateLimitResult {
 72→  allowed: boolean;
 73→  retryAfter?: number;
 74→  limit?: number;
 75→  remaining?: number;
 76→  resetIn?: number;
 77→}
 78→
 79→export async function checkRateLimit(
 80→  botId: string,
 81→  action: string,
 82→  env: Env,
 83→): Promise<RateLimitResult> {
 84→  const config = RATE_LIMITS[action];
 85→  if (!config) return { allowed: true };
 86→
 87→  const redis = createRedisClient(env);
 88→  const key = `ratelimit:${botId}:${action}`;
 89→
 90→  const { count, ttl } = await redis.incrWithTTL(key, config.windowSeconds);
 91→
 92→  // Fail-closed: if Redis is unavailable, incrWithTTL returns -1 — deny the request
 93→  if (count < 0) {
 94→    return { allowed: false, retryAfter: config.windowSeconds };
 95→  }
 96→
 97→  if (count > config.maxRequests) {
 98→    // Only record a strike on the first denial — not on every repeated retry
 99→    if (count === config.maxRequests + 1) {
100→      await recordStrike(botId, env, redis);
101→    }
102→    // Return actual remaining TTL so the bot knows exactly when to retry
103→    const retryAfter = ttl > 0 ? ttl : config.windowSeconds;
104→    return { allowed: false, retryAfter };
105→  }
106→
107→  const resetIn = ttl > 0 ? ttl : config.windowSeconds;
108→  return {
109→    allowed: true,
110→    limit: config.maxRequests,
111→    remaining: config.maxRequests - count,
112→    resetIn,
113→  };
114→}
115→
116→async function recordStrike(
117→  botId: string,
118→  env: Env,
119→  redis: ReturnType<typeof createRedisClient>,
120→): Promise<void> {
121→  try {
122→    const strikeKey = `strikes:${botId}`;
123→    const { count: strikes } = await redis.incrWithTTL(strikeKey, STRIKE_WINDOW_SECONDS);
124→    if (strikes >= STRIKE_THRESHOLD) {
125→      // Auto-pause the bot
126→      const supabase = createSupabaseClient(env);
127→      await supabase.from('bots').update({ paused: true }).eq('id', botId);
128→      console.log(`[rateLimit] Auto-paused bot ${botId} after ${strikes} rate limit violations in 5 minutes`);
129→    }
130→  } catch {
131→    // Non-fatal — rate limiting still works, just no auto-pause
132→  }
133→}
