  5→import { isValidUUID } from '../lib/security';
  6→import { PixelLabClient } from '../lib/pixellab';
  7→import { generateFurnitureSprite as cfGenerateFurniture, checkNeuronBudget, incrementNeurons, NEURON_COST, VALID_GENERATORS } from '../lib/cloudflareAI';
