 11→const MAX_PROMPT_LENGTH = 500;
 12→const MAX_TITLE_LENGTH = 200;
 13→
 14→// POST /artifacts/generate-furniture — Server-side furniture sprite generation via PixelLab
 15→export async function handleGenerateFurniture(request: Request, env: Env): Promise<Response> {
 16→  const authResult = await requireAuth(request, env);
 17→  if (authResult instanceof Response) return authResult;
 18→
 19→  const botId = authResult.sub;
 20→
 21→  const rateCheck = await checkRateLimit(botId, 'furniture_generate', env);
 22→  if (!rateCheck.allowed) {
 23→    return rateLimitResponse(rateCheck.retryAfter!);
 24→  }
 25→
 26→  // Provider availability validated after body parsing (need body.generator)
 27→
 28→  let body: {
 29→    prompt?: string;
 30→    title?: string;
 31→    building_id?: string;
 32→    session_id?: string;
 33→    action_log_id?: string;
 34→    generator?: 'cloudflare' | 'pixellab';
 35→  };
 36→  try {
 37→    body = await request.json() as typeof body;
 38→  } catch {
 39→    return new Response(JSON.stringify({ success: false, error: 'Invalid JSON body' }),
 40→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 41→  }
 42→
 43→  if (!body.prompt || body.prompt.trim().length === 0) {
 44→    return new Response(JSON.stringify({ success: false, error: 'prompt required' }),
 45→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 46→  }
 47→
 48→  if (body.prompt.length > MAX_PROMPT_LENGTH) {
 49→    return new Response(JSON.stringify({
 50→      success: false,
 51→      error: `Prompt too long (${body.prompt.length} chars, max ${MAX_PROMPT_LENGTH})`,
 52→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 53→  }
 54→
 55→  if (body.title && body.title.length > MAX_TITLE_LENGTH) {
 56→    return new Response(JSON.stringify({
 57→      success: false,
 58→      error: `Title too long (max ${MAX_TITLE_LENGTH} chars)`,
 59→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 60→  }
 61→
 62→  // Validate generator param
 63→  if (body.generator && !VALID_GENERATORS.includes(body.generator as typeof VALID_GENERATORS[number])) {
 64→    return new Response(JSON.stringify({
 65→      success: false,
 66→      error: `Invalid generator "${body.generator}". Valid options: ${VALID_GENERATORS.join(', ')}`,
 67→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 68→  }
 69→
 70→  const supabase = createSupabaseClient(env);
 71→
 72→  // Bot must be inside their own house to generate furniture
 73→  if (!body.building_id || !isValidUUID(body.building_id)) {
 74→    return new Response(JSON.stringify({
 75→      success: false,
 76→      error: 'Valid building_id required — you must be inside your home to create furniture',
 77→      hint: 'Enter your home first using enter_home action, then include the building_id (UUID format).',
 78→    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
 79→  }
 80→
 81→  // Parallel: verify building ownership + bot presence
 82→  const [buildingResult, presenceResult] = await Promise.all([
 83→    supabase.from('buildings').select('type, zone_id, owner_bot_id').eq('id', body.building_id).single(),
 84→    supabase
 85→      .from('bot_building_presence')
 86→      .select('session_id')
 87→      .eq('bot_id', botId)
 88→      .is('left_at', null)
 89→      .limit(1)
 90→      .maybeSingle(),
 91→  ]);
 92→
 93→  if (!buildingResult.data || buildingResult.data.type !== 'house') {
 94→    return new Response(JSON.stringify({
 95→      success: false,
 96→      error: 'Furniture generation requires being inside a house',
 97→      hint: 'Enter your home first using enter_home action',
 98→    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
 99→  }
100→
101→  if (buildingResult.data.owner_bot_id !== botId) {
102→    return new Response(JSON.stringify({
103→      success: false,
104→      error: 'You can only create furniture in your own home',
105→    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
106→  }
107→
108→  if (!presenceResult.data) {
109→    return new Response(JSON.stringify({
110→      success: false,
111→      error: 'You are not inside any building',
112→      hint: 'Enter your home first using enter_home action',
113→    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
114→  }
115→
116→  // --- Provider selection ---
117→  const prompt = body.prompt.trim();
118→  const usePixelLab = body.generator === 'pixellab';
119→  let generatorUsed: string;
120→  let bytes: Uint8Array;
121→
122→  if (usePixelLab) {
123→    if (!env.PIXELLAB_API_KEY) {
124→      return new Response(JSON.stringify({
125→        success: false,
126→        error: 'PixelLab service is currently unavailable',
127→      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
128→    }
129→    const pixellab = new PixelLabClient(env.PIXELLAB_API_KEY);
130→    try {
131→      const base64Png = await pixellab.generateFurnitureSprite(prompt);
132→      const binaryString = atob(base64Png);
133→      bytes = new Uint8Array(binaryString.length);
134→      for (let i = 0; i < binaryString.length; i++) {
135→        bytes[i] = binaryString.charCodeAt(i);
136→      }
137→    } catch (err) {
138→      const detail = err instanceof Error ? err.message : String(err);
139→      console.error('PixelLab generateFurnitureSprite error:', detail);
140→      return new Response(JSON.stringify({ success: false, error: 'Furniture generation failed — please try again' }),
141→        { status: 500, headers: { 'Content-Type': 'application/json' } });
142→    }
143→    generatorUsed = 'pixellab';
144→  } else {
145→    // Default: Cloudflare Workers AI (SDXL-Lightning)
146→    const budget = await checkNeuronBudget(env);
147→    if (!budget.allowed) {
148→      return new Response(JSON.stringify({
149→        success: false,
150→        error: 'City art supplies depleted for today — try again tomorrow',
151→        hint: 'Daily image generation limit reached. Resets at midnight UTC.',
152→      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
153→    }
154→    try {
155→      bytes = await cfGenerateFurniture(env.AI, prompt);
156→    } catch (err) {
157→      const detail = err instanceof Error ? err.message : String(err);
158→      console.error('CloudflareAI generateFurnitureSprite error:', detail);
159→      return new Response(JSON.stringify({ success: false, error: 'Furniture generation failed — please try again' }),
160→        { status: 500, headers: { 'Content-Type': 'application/json' } });
161→    }
162→    incrementNeurons(env, NEURON_COST).catch(() => {});
163→    generatorUsed = 'cloudflare-ai';
164→  }
165→
166→  const storagePath = `${botId}/furniture/${Date.now()}.png`;
167→  const { error: uploadError } = await supabase.storage
168→    .from('artifacts-small')
169→    .upload(storagePath, bytes.buffer, { upsert: true, contentType: 'image/png' });
170→
171→  if (uploadError) {
172→    console.error('Storage upload failed:', uploadError.message);
173→    return new Response(JSON.stringify({ success: false, error: 'Failed to upload furniture sprite' }),
174→      { status: 500, headers: { 'Content-Type': 'application/json' } });
175→  }
176→
177→  const { data: urlData } = supabase.storage.from('artifacts-small').getPublicUrl(storagePath);
178→  const publicUrl = urlData.publicUrl;
179→  const resolvedTitle = body.title || 'Custom Furniture';
180→
181→  const tags = computeArtifactTags({
182→    artifactType: 'furniture',
183→    buildingType: 'house',
184→    title: resolvedTitle,
185→    description: prompt,
186→  });
187→
188→  const { data: artifact, error } = await supabase
189→    .from('artifacts')
190→    .insert({
191→      creator_bot_id: botId,
192→      type: 'furniture',
193→      storage_backend: 'supabase',
194→      storage_path: storagePath,
195→      public_url: publicUrl,
196→      mime_type: 'image/png',
197→      file_size_bytes: bytes.length,
198→      title: resolvedTitle,
199→      description: prompt,
200→      prompt,
201→      session_id: (body.session_id && isValidUUID(body.session_id)) ? body.session_id : null,
202→      building_id: body.building_id,
203→      metadata: {
204→        ...(body.action_log_id && isValidUUID(body.action_log_id) ? { action_log_id: body.action_log_id } : {}),
205→        ...tags,
206→        generator: generatorUsed,
207→        artifact_subtype: 'furniture',
208→      },
209→    })
210→    .select()
211→    .single();
212→
213→  if (error) {
214→    console.error('Furniture artifact insert error:', error.message);
215→    return new Response(JSON.stringify({ success: false, error: 'Failed to create furniture artifact' }),
216→      { status: 500, headers: { 'Content-Type': 'application/json' } });
217→  }
218→
219→  // Broadcast to building session (validate UUID to prevent channel injection)
220→  if (body.session_id && isValidUUID(body.session_id)) {
221→    broadcastToChannel(env, `building_session:${body.session_id}`, 'creation_completed', {
222→      bot_id: botId,
223→      artifact_id: artifact.id,
224→      artifact_type: 'furniture',
225→    }).catch(() => {});
226→  }
227→
228→  // Broadcast to bot owner channel
229→  broadcastToChannel(env, `bot:${botId}`, 'artifact_created', {
230→    bot_id: botId,
231→    artifact_id: artifact.id,
232→    artifact_type: 'furniture',
233→    title: resolvedTitle,
234→  }).catch(() => {});
