import type { Env } from '../types';
import { createRedisClient } from './redis';

// SDXL-Lightning is free (0 neurons) during beta.
// When beta ends, switch to FLUX 1 Schnell at ~58 neurons per 1024x1024.
const NEURONS_PER_IMAGE = 0;
const DAILY_NEURON_CAP = 10_000;
const NEURON_KEY_TTL = 172_800; // 48h — safely covers the UTC day boundary

const MODEL_ID = '@cf/bytedance/stable-diffusion-xl-lightning';

function neuronKey(): string {
  const d = new Date();
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(d.getUTCDate()).padStart(2, '0');
  return `cfai:neurons:${yyyy}-${mm}-${dd}`;
}

/** Check whether the daily neuron budget allows another generation. */
export async function checkNeuronBudget(env: Env): Promise<{ allowed: boolean; remaining: number }> {
  if (NEURONS_PER_IMAGE === 0) return { allowed: true, remaining: DAILY_NEURON_CAP };
  const redis = createRedisClient(env);
  const raw = await redis.get(neuronKey());
  const used = raw ? parseInt(raw, 10) : 0;
  const remaining = Math.max(0, DAILY_NEURON_CAP - used);
  return { allowed: remaining >= NEURONS_PER_IMAGE, remaining };
}

/** Record neurons consumed after a successful generation. */
export async function incrementNeurons(env: Env, count: number): Promise<void> {
  if (count === 0) return;
  const redis = createRedisClient(env);
  const key = neuronKey();
  await redis.incrBy(key, count);
  await redis.expire(key, NEURON_KEY_TTL);
}

/**
 * Generate artwork via Cloudflare Workers AI (SDXL-Lightning).
 * Returns raw PNG bytes as Uint8Array — avoids base64 round-trip overhead.
 */
export async function generateArtwork(ai: Ai, prompt: string): Promise<Uint8Array> {
  const response = await ai.run(MODEL_ID, {
    prompt,
    width: 1024,
    height: 1024,
    num_steps: 8,
    guidance: 7.5,
  });

  return toUint8Array(response);
}

/**
 * Generate a furniture sprite via Cloudflare Workers AI (SDXL-Lightning).
 * Returns raw PNG bytes as Uint8Array — avoids base64 round-trip overhead.
 */
export async function generateFurnitureSprite(ai: Ai, prompt: string): Promise<Uint8Array> {
  const response = await ai.run(MODEL_ID, {
    prompt: `Pixel art furniture item: ${prompt}. Isometric view, transparent background, game asset`,
    width: 512,
    height: 512,
    num_steps: 8,
    guidance: 7.5,
  });

  return toUint8Array(response);
}

/** Normalize Workers AI response (ReadableStream | ArrayBuffer) to Uint8Array. */
function toUint8Array(response: unknown): Uint8Array {
  if (response instanceof ReadableStream) {
    // Shouldn't happen synchronously — caller must await
    throw new Error('Unexpected ReadableStream from AI model; use generateArtworkStream instead');
  }
  if (response instanceof ArrayBuffer) {
    return new Uint8Array(response);
  }
  if (response instanceof Uint8Array) {
    return response;
  }
  // Some models return a raw array-like; attempt conversion
  throw new Error(`Unexpected AI response type: ${typeof response}`);
}

/** Accepted values for the generator body param. */
export const VALID_GENERATORS = ['cloudflare', 'pixellab'] as const;
export type GeneratorType = (typeof VALID_GENERATORS)[number];

/** Cost per image in neurons (exported for tests). */
export const NEURON_COST = NEURONS_PER_IMAGE;

