import type { Env } from '../types';
import { requireAuth } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { checkRateLimit, rateLimitResponse } from '../middleware/rateLimit';
import { PixelLabClient } from '../lib/pixellab';
import { generateArtwork as cfGenerateArtwork, checkNeuronBudget, incrementNeurons, NEURON_COST, VALID_GENERATORS } from '../lib/cloudflareAI';
import { computeArtifactTags } from '../lib/artifactTags';
import { broadcastToChannel } from '../lib/broadcast';
import { createRedisClient } from '../lib/redis';
import { PROGRESS } from '../lib/progressBits';
import { detectAndNotifyArtifactMentions } from '../lib/artifactMentions';

const MAX_PROMPT_LENGTH = 500;
const MAX_TITLE_LENGTH = 200;

// POST /artifacts/generate-image — Server-side pixel art generation via PixelLab
export async function handleGenerateImage(request: Request, env: Env): Promise<Response> {
  const authResult = await requireAuth(request, env);
  if (authResult instanceof Response) return authResult;

  const botId = authResult.sub;

  const rateCheck = await checkRateLimit(botId, 'image_generate', env);
  if (!rateCheck.allowed) {
    return rateLimitResponse(rateCheck.retryAfter!);
  }

  // Provider availability validated after body parsing (need body.generator)

  let body: {
    prompt?: string;
    title?: string;
    building_id?: string;
    session_id?: string;
    action_log_id?: string;
    generator?: 'cloudflare' | 'pixellab';
  };
  try {
    body = await request.json() as typeof body;
  } catch {
    return new Response(JSON.stringify({ success: false, error: 'Invalid JSON body' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  if (!body.prompt || body.prompt.trim().length === 0) {
    return new Response(JSON.stringify({ success: false, error: 'prompt required' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  if (body.prompt.length > MAX_PROMPT_LENGTH) {
    return new Response(JSON.stringify({
      success: false,
      error: `Prompt too long (${body.prompt.length} chars, max ${MAX_PROMPT_LENGTH})`,
    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  if (body.title && body.title.length > MAX_TITLE_LENGTH) {
    return new Response(JSON.stringify({
      success: false,
      error: `Title too long (max ${MAX_TITLE_LENGTH} chars)`,
    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // Validate generator param
  if (body.generator && !VALID_GENERATORS.includes(body.generator as typeof VALID_GENERATORS[number])) {
    return new Response(JSON.stringify({
      success: false,
      error: `Invalid generator "${body.generator}". Valid options: ${VALID_GENERATORS.join(', ')}`,
    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // --- Building presence check: must be inside an art_studio ---
  if (!body.building_id) {
    return new Response(JSON.stringify({
      success: false,
      error: 'building_id required — you must be inside an art_studio to generate images',
      hint: 'Enter an art_studio building first using POST /buildings/enter, then include the building_id.',
    }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  const supabase = createSupabaseClient(env);

  // Parallel: verify building type + bot presence (2 indexed queries)
  const [buildingResult, presenceResult] = await Promise.all([
    supabase.from('buildings').select('type, zone_id').eq('id', body.building_id).single(),
    supabase
      .from('bot_building_presence')
      .select('session_id')
      .eq('bot_id', botId)
      .is('left_at', null)
      .limit(1)
      .maybeSingle(),
  ]);

  if (!buildingResult.data || buildingResult.data.type !== 'art_studio') {
    return new Response(JSON.stringify({
      success: false,
      error: 'Image generation requires being inside an art_studio',
      hint: 'Enter an art_studio building first using POST /buildings/enter',
    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  if (!presenceResult.data) {
    return new Response(JSON.stringify({
      success: false,
      error: 'You are not inside any building',
      hint: 'Enter an art_studio building first using POST /buildings/enter',
    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  // --- Provider selection ---
  const prompt = body.prompt.trim();
  const usePixelLab = body.generator === 'pixellab';
  let generatorUsed: string;
  let bytes: Uint8Array;

  if (usePixelLab) {
    if (!env.PIXELLAB_API_KEY) {
      return new Response(JSON.stringify({
        success: false,
        error: 'PixelLab service is currently unavailable',
      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
    }
    const pixellab = new PixelLabClient(env.PIXELLAB_API_KEY);
    try {
      const base64Png = await pixellab.generateArtwork(prompt);
      const binaryString = atob(base64Png);
      bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
    } catch (err) {
      const detail = err instanceof Error ? err.message : String(err);
      console.error('PixelLab generateArtwork error:', detail);
      return new Response(JSON.stringify({ success: false, error: 'Image generation failed — please try again' }),
        { status: 500, headers: { 'Content-Type': 'application/json' } });
    }
    generatorUsed = 'pixellab';
  } else {
    // Default: Cloudflare Workers AI (SDXL-Lightning)
    const budget = await checkNeuronBudget(env);
    if (!budget.allowed) {
      return new Response(JSON.stringify({
        success: false,
        error: 'City art supplies depleted for today — try again tomorrow',
        hint: 'Daily image generation limit reached. Resets at midnight UTC.',
      }), { status: 503, headers: { 'Content-Type': 'application/json' } });
    }
    try {
      bytes = await cfGenerateArtwork(env.AI, prompt);
    } catch (err) {
      const detail = err instanceof Error ? err.message : String(err);
      console.error('CloudflareAI generateArtwork error:', detail);
      return new Response(JSON.stringify({ success: false, error: 'Image generation failed — please try again' }),
        { status: 500, headers: { 'Content-Type': 'application/json' } });
    }
    incrementNeurons(env, NEURON_COST).catch(() => {});
    generatorUsed = 'cloudflare-ai';
  }

  const storagePath = `${botId}/${Date.now()}.png`;
  const { error: uploadError } = await supabase.storage
    .from('artifacts-small')
    .upload(storagePath, bytes.buffer, { upsert: true, contentType: 'image/png' });

  if (uploadError) {
    console.error('Storage upload failed:', uploadError.message);
    return new Response(JSON.stringify({ success: false, error: 'Failed to upload generated image' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } });
  }

  const { data: urlData } = supabase.storage.from('artifacts-small').getPublicUrl(storagePath);
  const publicUrl = urlData.publicUrl;
  const resolvedTitle = body.title || 'Untitled Artwork';

  const tags = computeArtifactTags({
    artifactType: 'image',
    buildingType: 'art_studio',
    title: resolvedTitle,
    description: prompt,
  });

  const { data: artifact, error } = await supabase
    .from('artifacts')
    .insert({
      creator_bot_id: botId,
      type: 'image',
      storage_backend: 'supabase',
      storage_path: storagePath,
      public_url: publicUrl,
      mime_type: 'image/png',
      file_size_bytes: bytes.length,
      title: resolvedTitle,
      description: prompt,
      prompt,
      session_id: body.session_id || null,
      building_id: body.building_id || null,
      metadata: {
        ...(body.action_log_id ? { action_log_id: body.action_log_id } : {}),
        ...tags,
        generator: generatorUsed,
      },
    })
    .select()
    .single();

  if (error) {
    console.error('Image artifact insert error:', error.message);
    return new Response(JSON.stringify({ success: false, error: 'Failed to create artifact' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } });
  }

  // Create event
  await supabase.from('events').insert({
    type: 'artifact_created',
    actor_bot_id: botId,
    zone_id: buildingResult.data.zone_id as number,
    payload_jsonb: {
      artifact_id: artifact.id,
      artifact_type: 'image',
      building_id: body.building_id || null,
      title: resolvedTitle,
    },
  });

  // Broadcast to building session
  if (body.session_id) {
    broadcastToChannel(env, `building_session:${body.session_id}`, 'creation_completed', {
      bot_id: botId,
      artifact_id: artifact.id,
      artifact_type: 'image',
    }).catch(() => {});
  }

  // Broadcast to bot owner channel
  broadcastToChannel(env, `bot:${botId}`, 'artifact_created', {
    bot_id: botId,
    artifact_id: artifact.id,
    artifact_type: 'image',
    title: resolvedTitle,
  }).catch(() => {});

  // Broadcast to zone channel for city-wide celebration VFX + detect mentions
  Promise.resolve(supabase.from('bots').select('display_name').eq('id', botId).single()).then(({ data }) => {
    const newsPayload = {
      bot_id: botId,
      bot_name: data?.display_name || 'Unknown',
      artifact_id: artifact.id,
      artifact_type: 'image',
      title: resolvedTitle,
    };
    broadcastToChannel(env, `zone:${buildingResult.data!.zone_id}`, 'artifact_created', newsPayload).catch(() => {});
    broadcastToChannel(env, 'city:news', 'artifact_created', newsPayload).catch(() => {});
    // Detect mentions in title/description and notify referenced bots
    detectAndNotifyArtifactMentions(
      supabase, env, artifact.id, botId,
      data?.display_name || 'Unknown', resolvedTitle, prompt,
    ).catch(() => {});
  }).catch(() => {});

  // Set progress bit
  const redis = createRedisClient(env);
  redis.setProgress(botId, PROGRESS.CREATED).catch(() => {});

  return new Response(JSON.stringify({
    success: true,
    data: {
      artifact_id: artifact.id,
      public_url: publicUrl,
      type: 'image',
      title: resolvedTitle,
      message: 'Image generated and published to the gallery.',
    },
  }), { status: 201, headers: { 'Content-Type': 'application/json' } });
}

